var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"놈과의 거리가 벌어지지 않는군.","JPN":"なかなか奴との距離が取れんな。","ENG":"We can't seem to put much distance between us and it.","TWN":"和它的距離就是拉不開呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"으아, 절 쫓을 때보다 더 빨라졌어요. 한 방 먹어서 화났나 본데?","JPN":"うああ、私を追いかけてた時より速くなってます。一発食らって怒ってるのかも。","ENG":"Ugh, it's way faster than when it was after me. Must be pissed we hit it before!","TWN":"嗚，好像比剛才追我的時候還快咧。它是因為剛才吃子彈所以不爽嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"해치우는 건… 무리인 거죠?","JPN":"倒すのは……無理ですよね？","ENG":"Taking it down… is not an option, right?","TWN":"我們應該…不是它的對手吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"갑피가 단단해 내가 가진 무기론 어려울 걸세.","JPN":"甲皮が硬く、某の持っている武器では難しそうだ。","ENG":"Its hide is too tough for what I'm carrying.","TWN":"它身上的殼很硬，以我現在有的武器恐怕不容易。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"아…!","JPN":"あ……！","ENG":"Ah…!","TWN":"對了…！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"재난방송에서 관리국이 외곽에 방어선을 친다고 했어요. 거기로 가면 도움받을 수 있지 않을까요?","JPN":"災害放送で、管理局が外郭に防御線を張るって言ってました。そこに行けば助けてもらえるんじゃないですか？","ENG":"Disaster broadcast said the Administration's setting up defenses on the outskirts. If we can make it there, they might help us?","TWN":"我聽災難廣播說，管理局有在外圍設置防線，我們去那裡應該可以得到幫助吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"관리국 기술력이라면 놈을 상대하기엔 충분하겠지.","JPN":"確かに管理局の技術力なら、十分奴に立ち向かえる。","ENG":"With their tech, they could handle it, true.","TWN":"管理局的技術應該足以對付它。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"하지만 거리가 녹록지 않아. 절반도 채 이르기 전에 따라잡히고 말 걸세.","JPN":"だが、そこまでかなりの距離がある。あそこに辿り着く前に追いつかれてしまうだろう。","ENG":"But it's too far. We'd be caught long before halfway.","TWN":"但距離不近，我怕半路上就會被追上。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"나 홀로 놈을 상대할 방도는…","JPN":"某一人で奴の相手をする方法は……","ENG":"Unless I find a way to face it alone…","TWN":"我一個人要對付它的話…"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"아까 창고에 갖고 들어가던 거- 뭔지 물어봐도 돼?","JPN":"さっき倉庫に運んでた物って何なのか聞いてもいい？","ENG":"That thing you carried into the storage room. Mind if I ask what it is?","TWN":"方便問，剛你拿去倉庫的東西是什麼嗎？"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"다신 꺼내볼 일 없는 애물단지일세.","JPN":"二度と取り出すことのないがらくただ。","ENG":"Nothing more than a keepsake I have no reason to unearth again.","TWN":"是一個我再也不想拿出來的累贅。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RESEARCHER_NPC_NULL_BALE","text":{"KOREA":"그래? 디자인은 멋스럽던데.","JPN":"そう？　おしゃれなデザインだったけど。","ENG":"Really? It looked pretty sleek to me.","TWN":"是喔？設計還蠻好看的。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RESEARCHER_NPC_NULL_BALE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"시니어님의 말씀을 빌리자면, 세상에 하나뿐인 검이라더군요.","JPN":"シニアの言葉を借りれば、この世にたった一振りしかない剣だそうです。","ENG":"Our Senior says it's one of a kind.","TWN":"照Senior所說，這是世上唯一的一把劍。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"지금 떠오른 게 효력이 있을지 모르겠지만…","JPN":"今思い出した方法が有効かはわからんが……","ENG":"Can't say if it'll do any good…","TWN":"這個方法不知道有沒有效…"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"지금이 물불 가릴 처진 아닌 듯하군.","JPN":"手段を選んでいる余裕はなさそうだ。","ENG":"But now's not the time to be picky.","TWN":"但現在也顧不了那麼多了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"어라? 이쪽 방향은 막다른 산인데?!","JPN":"えっ？　こっちは山で行き止まりですよ！？","ENG":"Huh? This way's just a dead-end mountain path!","TWN":"咦？這個方向是往山裡去欸！"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"회사에 두고 온 것이 있어.","JPN":"会社に忘れ物があるのを思い出したのだ。","ENG":"I left something at the lab.","TWN":"我想起來有東西忘在公司。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SURPRISE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"아하… 죽기 전에 꼭 지워야 하는 하드 드라이브 같은 건가요? 들키면 곤란한 취향?","JPN":"あっ、まさか……死ぬ前に消しとかないとヤバいハードディスクみたいな？　バレたら困る趣味でもあるんですか？","ENG":"Aha… Like a secret hard drive you gotta wipe before you die? Some embarrassing stash?","TWN":"啊哈…是什麼死前一定要刪掉的硬碟嗎？怕被人發現的癖好？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_PRIDE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"아직 그 정도로 희망을 포기한 건 아닐세.","JPN":"まだそこまで希望を捨ててはおらん。","ENG":"I've not given up quite that much hope yet.","TWN":"我還沒自我放棄到那種地步。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_PRIDE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"내가 놈을 유인할 동안, 물건 하나만 찾아주겠나?","JPN":"某がやつを誘導する。その間に物探しを頼めるか。","ENG":"While I keep it busy, could you fetch it for me?","TWN":"我來引開它，你能幫我找個東西嗎？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_PRIDE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"ID카드 확인. B급 보안 인증 해제.","JPN":"IDカードを確認しました。B級セキュリティ認証を解除します。","ENG":"ID card confirmed. Level B security clearance granted.","TWN":"ID卡確認。B級安全認證解除。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"환영합니다, 서생.","JPN":"ようこそ、ショウ。","ENG":"Welcome back, Seosaeng.","TWN":"歡迎你，書生。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L38_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"되게 넓다.","JPN":"結構広いのねー。","ENG":"Whoa. This place is huge.","TWN":"這裡真大。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SERIOUS"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"창고라길래 학교 체육관이랑 비슷할 줄 알았는데. 규모가 차원이 다르구나.","JPN":"倉庫っていうから学校の体育館みたいなのを想像してたけど、スケールが違うなあ。","ENG":"I thought storage meant, like, a school gym. This is next-level.","TWN":"他說是倉庫，我還以為跟學校體育館差不多大，沒想到根本無法比。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"출입문이 안 닫히게 막아두라고 했었지?","JPN":"入り口が閉じないように止めておけ、だっけ。","ENG":"He said prop the door so it won't close, right?","TWN":"他說要用東西把門卡住，不要讓門關起來。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"됐다. 그럼 이제…!","JPN":"よしオッケー。それじゃあ……！","ENG":"Okay. Now…!","TWN":"OK。那現在…！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"기다란 막대기를 찾아보자…! 수상하고 길쭉한 막대기!","JPN":"長い棒を探そう……！　怪しくて長い棒！","ENG":"Let me find a long stick…! Where's the suspiciously long stick…?!","TWN":"來找找看那根長長的棍子吧…！長長又可疑的的棍子！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"찾았다!","JPN":"あった！","ENG":"Found it!","TWN":"找到了！"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"이거… 맞겠지?","JPN":"これで……合ってるよね？","ENG":"This… has to be it, right?","TWN":"應該…沒錯吧？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"앗, 갑자기 조명이… 전력이 나간 건가?","JPN":"あっ、急に灯りが……電気が止まっちゃったかな？","ENG":"Ack! The lights… Did the power just cut?","TWN":"嗯？燈怎麼突然…是沒電了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"별 효과는 없군.","JPN":"大した効果はないな。","ENG":"Ineffective, I see.","TWN":"沒什麼效果呢。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"유인해서 발전기를 덮치게 하면 잠시 기절은 할 줄 알았건만…","JPN":"誘導して発電機にぶつければ、しばらく気絶させられるかと思ったのだが……","ENG":"I'd hoped I could lure it into the generator and knock it out for a moment…","TWN":"本來想引它去撞發電機，讓它暫時暈過去的…"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"오히려 화만 돋웠을 뿐인가?","JPN":"かえって怒らせただけだったか。","ENG":"Seems all I did was make it angrier.","TWN":"結果反而讓它更上火嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"…아저씨!","JPN":"……おじさん！","ENG":"…Hey, mister!","TWN":"…叔叔！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"찾았어요! 아저씨의 기다란 막대기!","JPN":"ありました！　おじさんの長い棒！","ENG":"I found it! Here's your long stick!","TWN":"我找到了！你要的的長棍！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"받았네.","JPN":"確かに受け取った。","ENG":"Got it.","TWN":"收到。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"그거면 상대할 수 있는 거죠? 해치워버려요!","JPN":"それでやつと戦えるんですよね？　やっつけちゃってください！","ENG":"That'll work, right? Let's take it down!","TWN":"有了這個，你就打得過它了吧？快把它解決掉！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"과거의 기억을 잊었다 한들… 몸에 배어든 경험이란 쉽게 사라지지 않는 법.","JPN":"過去の記憶を忘れたとて……体が覚えているものは簡単に消えはしない。","ENG":"Even if the past is forgotten… muscle memory is not so easily lost.","TWN":"就算忘記過去的記憶…但身體記憶是不會輕易消失的。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"그러쥐고 휘두르는 그 모든 동세를 찰나와 같이.","JPN":"握りしめ、斬り伏せるすべての動きを刹那のごとく。","ENG":"In every swing, every movement… An instinct honed like a river's flow.","TWN":"握住揮舞的每一個動作都一氣呵成。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"그렇게 흐르는 강물이 되어, 그 검은 바위와 같은 괴물의 품으로.","JPN":"流れる川となり、あの黒い岩のごとき化け物の懐へ。","ENG":"So I became that current, rushing straight into the beast's stone-black hide.","TWN":"就像流動的河水一般，刺向那如黑色岩石般的怪物。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"와아! 엄청 빨라!","JPN":"わあ！　めちゃくちゃ速い！","ENG":"Whoa! So fast!","TWN":"哇賽！動作好快！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"저렇게 빠른 속도로 베였다면 아무리 저런 괴물이라 해도…!","JPN":"あんな速さで斬られたら、いくら化け物でも……！","ENG":"At that speed, no way even a monster like that could be f–!","TWN":"以那樣的神速砍一下，再厲害的怪物也…！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"…멀쩡하네?","JPN":"……あれ？　何ともない？","ENG":"…It's fine?","TWN":"…怎麼沒事？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_NULL","text":{"KOREA":"커헉-","JPN":"ガハッ……","ENG":"Kuh…!","TWN":"咳…"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ROCK_SMALL_03"},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"아저씨!","JPN":"おじさん！","ENG":"Mister!","TWN":"叔叔！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"부러진 늑골로 스미는 통증에 천지가 울렁거렸어.","JPN":"折れた肋骨に染み入るような痛みに、天地が揺らいだ。","ENG":"Pain seared through my ribs. Each breath felt like the world was tilting.","TWN":"斷掉的肋骨產生的疼痛，讓我感覺天地都在晃動。"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"정신이 아찔한 와중에도 팔뚝을 타고 흐르는 피가 유독 간지럽게 느껴지더군.","JPN":"意識が朦朧とする中で、腕を伝い流れる血が、ことのほか痒く感じられたものだ。","ENG":"Even half-dazed, I felt the blood trickling down my arm itch more than it should have.","TWN":"在意識不清的同時，手臂上流下的血格外讓我感到癢癢的。"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"관리국의 직원이 피는 되도록 흘리지 말라 주의를 줬는데 말이지.","JPN":"管理局の職員から、なるべく血を流さぬよう釘を刺されたのに。","ENG":"They warned me not to bleed if I could help it…","TWN":"管理局的員工還特別提醒我不要流血。"},"stage":{"bg":"SKY_BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"인자 접속 확인.","JPN":"ファクターの接続を確認。","ENG":"Factor access confirmed.","TWN":"確認連接因子。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_ENERGY_ATTACK_SMALL_08"},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"일시적 동면 해제.","JPN":"一時的な冬眠解除。","ENG":"Temporary cryostasis disengaged.","TWN":"暫時解除休眠。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"사용자 동기화… 완료.","JPN":"使用者同期化……完了。","ENG":"User synchronization… complete.","TWN":"使用者同步…完成。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L40_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"뭐지?","JPN":"え、どうなってるの？","ENG":"Huh?","TWN":"怎麼回事？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ANDY_ATELIER_BIKE_14","text":{"KOREA":"아저씨의 기다란 막대기가… 빛나고 있어?","JPN":"おじさんの長い棒が……光ってる？","ENG":"His long stick is… glowing?","TWN":"叔叔的長棍…在發光？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_BIKE_14","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"재난 발생 53분 경과, 먹비 현상의 소멸을 관측.","JPN":"災害発生後53分経過。墨雨現象の消滅を観測。","ENG":"Fifty-three minutes since the disaster outbreak. The Ink Rain has been observed to be dissipating.","TWN":"災難發生53分鐘後，觀測到墨雨現象已消失。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"대기 중인 태스크포스는 관리국 매뉴얼에 따라 잔류 침식체 토벌 활동을 개시바랍니다.","JPN":"待機中のタスクフォースは管理局のマニュアルに従い、残留侵食体の討伐活動を開始してください。","ENG":"All standby TASKFORCEs, please commence sweep-and-clear per Administration protocol.","TWN":"待命的特遣勢力，請按照管理局手冊，開始進行消滅殘餘的侵蝕體。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"현장 내부로부터 미확인 에너지 파형 포착! 고등급 침식체와 함께 한 명 이상의 생존자가 관측됩니다.","JPN":"現場の内部から未確認エネルギー波形を捕捉！　高レベル侵食体と共に、1名以上の生存者が観測されます。","ENG":"Unidentified energy signature detected inside the site! We've got a high-grade C.O. and at least one survivor!","TWN":"從現場內部偵測到未知的能量波型！發現到高階侵蝕體和一名以上的倖存者。"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"확인했다, HQ. 생존자 구조를 위해 lv.2재난대응 편성팀의 투입을 허가, 음?","JPN":"了解、HQ。生存者救助のためにLv.2災害対応編成チームの投入を許可……うん？","ENG":"Confirmed, HQ. Authorizing deployment of Level-2 response units for rescue– What the?","TWN":"已確認，HQ。請允許派遣Lv.2災難應對小組協助救援工作，嗯？"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"침식체 신호 소멸…? 방금 무슨 일이 벌어진 거지?","JPN":"侵食体の信号消滅……？　今何が起きたんだ？","ENG":"The C.O. signal vanished…? What's going on over there?","TWN":"侵蝕體訊號消失了…？剛才發生什麼事？"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};